using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketContext : DbContext
{
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer("YourConnectionStringHere");
    }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int QuantityAvailable { get; set; }
}

public class TicketService
{
    private readonly TicketContext _context;

    public TicketService(TicketContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTickets(int eventId, int quantity)
    {
        var ticket = await _context.Tickets
            .FirstOrDefaultAsync(t => t.EventId == eventId);

        if (ticket == null || ticket.QuantityAvailable < quantity)
        {
            return false;
        }

        lock (ticket)
        {
            if (ticket.QuantityAvailable >= quantity)
            {
                ticket.QuantityAvailable -= quantity;
                await _context.SaveChangesAsync();
                return true;
            }
        }

        return false;
    }
}